    Question(categoryId = 7, questionText = "Was beschreibt das Liskov Substitution Principle (LSP) in SOLID?", answerA = "Abgeleitete Klassen muessen als Ersatz fuer ihre Basisklassen verwendbar sein, ohne das Programmverhalten zu veraendern", answerB = "Klassen sollen nur eine einzige Verantwortung haben", answerC = "Abhaengigkeiten sollen auf Abstraktionen zeigen, nicht auf konkrete Implementierungen", answerD = "Software-Entitaeten sollen offen fuer Erweiterung, aber geschlossen fuer Aenderung sein", correctAnswer = 0, explanation = "Das LSP von Barbara Liskov besagt: Wenn S ein Subtyp von T ist, muss jedes Programm das T verwendet auch mit S korrekt funktionieren. Verletzungen fuehren zu unerwarteten Laufzeitfehlern.", difficulty = 3, funFact = "Barbara Liskov erhielt 2008 den Turing Award, teilweise fuer dieses Prinzip, das sie 1987 in einem Konferenzvortrag formulierte."),
    Question(categoryId = 7, questionText = "Was ist die Currying-Technik in der funktionalen Programmierung?", answerA = "Die Umwandlung einer Funktion mit mehreren Argumenten in eine Kette von Funktionen, die je ein Argument nehmen", answerB = "Das Zusammenfuehren mehrerer Funktionen zu einer einzigen Funktion durch Komposition", answerC = "Die rekursive Aufrufoptimierung durch Eliminierung von Stack-Frames", answerD = "Das Memoizieren von Funktionsergebnissen fuer reine Funktionen", correctAnswer = 0, explanation = "Currying transformiert f(a, b, c) in f(a)(b)(c). Jede Funktion nimmt ein Argument und gibt eine neue Funktion zurueck. Ermoeglicht partielle Applikation und Funktionskomposition.", difficulty = 3, funFact = "Currying ist nach Haskell Curry benannt, obwohl Moses Schoefinkel und Gottlob Frege das Konzept fruehzeitig entwickelten. Curry selbst nannte es 'Schoefinkeln'."),
    Question(categoryId = 7, questionText = "Welche Bedingungen muessen laut Coffman fuer einen Deadlock gleichzeitig erfuellt sein?", answerA = "Mutual Exclusion, Hold and Wait, No Preemption, Circular Wait", answerB = "Starvation, Livelock, Priority Inversion, Race Condition", answerC = "Synchronisation, Parallelitaet, Shared Memory, Message Passing", answerD = "Mutex, Semaphor, Monitor, Condition Variable", correctAnswer = 0, explanation = "Coffman et al. (1971) definierten vier notwendige Bedingungen fuer Deadlocks: (1) Gegenseitiger Ausschluss, (2) Hold-and-Wait, (3) Keine Preemption, (4) Zirkulaeres Warten. Alle vier muessen gleichzeitig gelten.", difficulty = 3, funFact = "Deadlock-Prevention durch Aufbrechen einer dieser Bedingungen: Banker's Algorithm verhindert zirkulaeres Warten durch sichere Ressourcen-Allokation."),
    Question(categoryId = 7, questionText = "Was ist Tail-Call-Optimierung (TCO) und warum ist sie in funktionalen Sprachen wichtig?", answerA = "Eine Compiler-Optimierung die rekursive Aufrufe in Tail-Position in Schleifen umwandelt, um Stack-Overflows bei tiefer Rekursion zu vermeiden", answerB = "Eine Technik um den letzten Funktionsaufruf im Programm zu beschleunigen", answerC = "Das Zwischenspeichern von Rekursionsergebnissen (Memoization)", answerD = "Die parallele Ausfuehrung von Tail-Calls auf mehreren CPU-Kernen", correctAnswer = 0, explanation = "TCO erkennt, dass ein rekursiver Aufruf in Tail-Position keinen eigenen Stack-Frame benoetigt - der aktuelle Frame wird wiederverwendet. Ermoeglicht endlose Rekursion ohne Stack-Overflow.", difficulty = 3, funFact = "Scheme war die erste Sprache die TCO mandatierte (1975). Haskell und Erlang unterstuetzen es. Python-Autor Guido van Rossum lehnte TCO bewusst ab um Stack-Traces lesbar zu halten."),
    Question(categoryId = 7, questionText = "Was ist ein Typ-1-Hypervisor und wie unterscheidet er sich von Typ-2?", answerA = "Typ-1 laeuft direkt auf der Hardware (Bare Metal) ohne Host-OS; Typ-2 laeuft als Prozess innerhalb eines Host-Betriebssystems", answerB = "Typ-1 unterstuetzt nur Windows-Gastbetriebssysteme, Typ-2 alle Betriebssysteme", answerC = "Typ-1 ist langsamer als Typ-2 wegen des fehlenden Host-OS-Treiber-Stacks", answerD = "Typ-2 hat direkten Hardwarezugriff, Typ-1 nur vermittelten Zugriff", correctAnswer = 0, explanation = "Typ-1-Hypervisoren (VMware ESXi, Microsoft Hyper-V, Xen) laufen direkt auf der Hardware und sind effizienter. Typ-2 (VirtualBox, VMware Workstation) laufen als Applikation im Host-OS und haben mehr Overhead.", difficulty = 3, funFact = "Der erste Hypervisor war CP-40 von IBM, entwickelt 1967. Er ermoeglichte mehrere gleichzeitige Nutzer auf einem IBM System/360."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen struktureller und nominaler Typisierung?", answerA = "Strukturelle Typisierung prueft die Struktur (Felder, Methoden) eines Typs; nominale Typisierung prueft den explizit deklarierten Typnamen", answerB = "Strukturelle Typisierung ist grundsaetzlich schwaecher als nominale Typisierung", answerC = "Nominale Typisierung wird ausschliesslich in dynamischen Sprachen eingesetzt", answerD = "Strukturelle Typisierung erfordert immer explizite Typannotationen vom Programmierer", correctAnswer = 0, explanation = "Go und TypeScript nutzen strukturelle Typisierung (duck typing): ein Typ passt wenn er die richtigen Methoden hat. Java und C# nutzen nominale Typisierung: ein Typ muss explizit als Subtyp deklariert sein.", difficulty = 3, funFact = "Haskell's Typklassen sind eine hybride Loesung: strukturell definiert, aber nominal registriert durch explizite Instanzdeklarationen."),
    Question(categoryId = 7, questionText = "Was ist das Dependency Inversion Principle (DIP) in SOLID?", answerA = "High-Level-Module sollen nicht von Low-Level-Modulen abhaengen; beide sollen von Abstraktionen abhaengen - implementiert durch Interfaces und Dependency Injection", answerB = "Jede Klasse soll alle ihre Abhaengigkeiten selbst im Konstruktor erzeugen", answerC = "Abhaengigkeiten sollen ausschliesslich durch direkte Vererbung ausgedrueckt werden", answerD = "Low-Level-Module definieren die Interfaces, High-Level-Module implementieren diese", correctAnswer = 0, explanation = "DIP kehrt die klassische Abhaengigkeitsrichtung um: statt dass BusinessLogic direkt von DatabaseImpl abhaengt, haengen beide von IRepository ab. Implementiert durch IoC-Container, Constructor Injection und Interface-Segregation.", difficulty = 3, funFact = "DIP ist die theoretische Grundlage fuer alle Dependency-Injection-Frameworks wie Spring, Dagger/Hilt (Android) und .NET's built-in DI."),
    Question(categoryId = 7, questionText = "Was ist das Konzept der algebraischen Datentypen (ADTs) in der Typentheorie?", answerA = "Typen die durch algebraische Operationen zusammengesetzt werden: Summentypen (ODER, Tagged Unions) und Produkttypen (UND, Records/Tupel)", answerB = "Datentypen die ausschliesslich numerische Werte und algebraische Ausdruecke speichern koennen", answerC = "Klassen in objektorientierten Sprachen mit Mehrfachvererbung", answerD = "Typen die automatisch und implizit zwischen Integer und Float konvertieren", correctAnswer = 0, explanation = "ADTs: Produkttypen (AND, Tupel/Records: A AND B) und Summentypen (OR, Tagged Unions: A OR B). Haskell's data, Rust's enum, Swift's enum mit Assoziationen. Ermoeglichen typsichere Modellierung ohne null.", difficulty = 3, funFact = "Die 'Billion-Dollar-Mistake' (null) von Tony Hoare (1965) waere mit ADTs vermieden worden. Rust's Option<T> und Haskell's Maybe sind Summentypen die null ersetzen."),
    Question(categoryId = 7, questionText = "Was ist ein Lock-Free-Algorithmus und wie unterscheidet er sich von einem Wait-Free-Algorithmus?", answerA = "Lock-Free garantiert dass mindestens ein Thread systemweiten Fortschritt macht; Wait-Free garantiert dass ALLE Threads in beschraenkter Zeit Fortschritt machen", answerB = "Lock-Free und Wait-Free sind Synonyme fuer dieselbe Eigenschaft", answerC = "Wait-Free ist schwaecher als Lock-Free wegen groesserer durchschnittlicher Latenz", answerD = "Lock-Free-Algorithmen koennen keine atomaren Operationen (CAS) verwenden", correctAnswer = 0, explanation = "Lock-Free: kein Mutex, aber ein Thread kann verhungern. Wait-Free: Starkste Garantie, jeder Thread macht in endlich vielen Schritten Fortschritt. Implementiert mit Compare-And-Swap (CAS) Instruktionen.", difficulty = 3, funFact = "jemalloc und tcmalloc nutzen Lock-Free-Techniken. Java's java.util.concurrent.atomic-Paket bietet Lock-Free-Primitives wie AtomicInteger auf Basis von CAS."),
    Question(categoryId = 7, questionText = "Was ist das Strategy-Pattern und in welchem Kontext ist es besonders nuetzlich?", answerA = "Das Strategy-Pattern definiert eine Familie von Algorithmen, kapselt jeden einzeln und macht sie austauschbar - nuetzlich wenn Algorithmusvarianten zur Laufzeit gewechselt werden muessen", answerB = "Das Strategy-Pattern speichert Algorithmen in einer externen Datenbank fuer spaetere Verwendung", answerC = "Das Strategy-Pattern ist funktional identisch mit dem Template-Method-Pattern", answerD = "Das Strategy-Pattern wird ausschliesslich in Single-Threaded-Anwendungen verwendet", correctAnswer = 0, explanation = "Strategy kapselt Algorithmen hinter einem Interface: PaymentStrategy mit CreditCard, PayPal, Crypto als Implementierungen. Der Context delegiert an die aktuelle Strategy. Gegensatz zu Switch-Case-Logik im Context.", difficulty = 3, funFact = "Strategy ist das Pattern hinter java.util.Comparator: Collections.sort() delegiert den Vergleich an eine austauschbare Comparator-Implementierung."),
    Question(categoryId = 7, questionText = "Was ist das Flyweight-Pattern und wann sollte es eingesetzt werden?", answerA = "Das Flyweight-Pattern teilt Objekte mit identischem intrinsischem Zustand um Speicher zu sparen, wenn sehr viele aehnliche Objekte benoetigt werden", answerB = "Das Flyweight-Pattern beschleunigt Objekterzeugung durch einen vorallokierten Object Pool", answerC = "Das Flyweight-Pattern ist eine leichtgewichtige Variante des Singleton-Patterns", answerD = "Das Flyweight-Pattern wird ausschliesslich fuer leichtgewichtige Hintergrund-Threads eingesetzt", correctAnswer = 0, explanation = "Flyweight trennt intrinsischen (unveraenderlich, geteilt) und extrinsischen (kontextspezifisch) Zustand. Java's String Interning und Integer Cache (-128 bis 127) sind Flyweight-Implementierungen.", difficulty = 3, funFact = "Klassisches Beispiel: ein Texteditor mit einer Million Zeichen. Statt 1 Mio. Character-Objekte werden 256 Flyweight-Objekte (je Zeichen ein Typ) geteilt. Speicherersparnis: bis zu 100x."),
    Question(categoryId = 7, questionText = "Was ist das Chain-of-Responsibility-Pattern und wie unterscheidet es sich vom Decorator?", answerA = "Chain of Responsibility gibt eine Anfrage durch eine Kette von Handlern weiter bis einer sie verarbeitet; Decorator fuegt immer Verhalten hinzu, Chain kann die Anfrage auch ablehnen oder stoppen", answerB = "Chain of Responsibility und Decorator sind funktional identisch und austauschbar", answerC = "Decorator verarbeitet Anfragen in umgekehrter Reihenfolge, Chain vorwaerts", answerD = "Chain of Responsibility wird ausschliesslich fuer Fehlerbehandlung und Exception Handling eingesetzt", correctAnswer = 0, explanation = "Decorator: jeder Decorator delegiert immer weiter. Chain of Responsibility: Handler entscheiden ob sie verarbeiten oder weiterleiten. HTTP Middleware-Pipelines (Express.js, ASP.NET) und Java Servlet Filter sind CoR-Implementierungen.", difficulty = 3, funFact = "Android's Touch Event System ist ein Chain-of-Responsibility: Wenn ein View ein Touch-Event nicht verarbeitet (onTouchEvent gibt false zurueck), wird es an den Parent-ViewGroup weitergereicht."),
    Question(categoryId = 7, questionText = "Was ist das Proxy-Pattern und welche drei Hauptvarianten existieren?", answerA = "Das Proxy-Pattern stellt einen Stellvertreter fuer ein Objekt bereit; Varianten: Virtual Proxy (lazy loading), Remote Proxy (Netzwerkobjekt), Protection Proxy (Zugriffskontrolle)", answerB = "Das Proxy-Pattern ist eine vereinfachte Form des Decorator-Patterns ohne Zustandsverwaltung", answerC = "Proxies sind nur in Netzwerkprotokollen und RPC-Systemen sinnvoll verwendbar", answerD = "Ein Proxy erhoecht grundsaetzlich immer die Latenz ohne messbaren Nutzen", correctAnswer = 0, explanation = "Virtual Proxy: erstellt teuere Objekte erst bei Bedarf. Remote Proxy: lokales Interface fuer entferntes Objekt (RPC, gRPC Stubs). Protection Proxy: prueft Berechtigungen vor Methodenaufruf.", difficulty = 3, funFact = "Java's Dynamic Proxies (java.lang.reflect.Proxy) und Kotlin's Delegation by keyword sind Proxy-Implementierungen. Spring AOP nutzt Dynamic Proxies extensiv fuer @Transactional und @Cacheable."),
    // correctAnswer = 1 (13x: Fragen 14-26)
    Question(categoryId = 7, questionText = "Welche Zeitkomplexitaet hat der Algorithmus von Dijkstra mit einem binaeren Min-Heap?", answerA = "O(V^2) ohne jede Optimierung", answerB = "O(E log V) mit binaer-Heap-Implementierung", answerC = "O(V log E) mit Fibonacci-Heap-Implementierung", answerD = "O(E + V) bei duennen Graphen", correctAnswer = 1, explanation = "Mit einem binaeren Min-Heap hat Dijkstra die Komplexitaet O((E + V) log V), oft vereinfacht als O(E log V). Mit einem Fibonacci-Heap erreicht man O(E + V log V).", difficulty = 3, funFact = "Edsger Dijkstra entwickelte seinen Algorithmus 1956 in etwa 20 Minuten ohne Papier und Bleistift waehrend einer Tasse Kaffee in einem Amsterdam-Cafe."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Mutex und einem Semaphor?", answerA = "Ein Mutex kann von mehreren Threads gleichzeitig gehalten werden, ein Semaphor nicht", answerB = "Ein Mutex ist ein binaerer gegenseitiger Ausschluss mit Eigentuemer-Konzept; ein Semaphor ist ein Zaehler der von beliebigen Threads erhoeht oder erniedrigt werden kann", answerC = "Semaphore sind schneller als Mutexe wegen Hardware-Optimierungen im Kernel", answerD = "Mutexe werden nur in User-Space verwendet, Semaphore ausschliesslich im Kernel-Space", correctAnswer = 1, explanation = "Ein Mutex hat einen Eigentuemer: nur der Thread, der ihn gesperrt hat, kann ihn freigeben. Ein Semaphor hat kein Eigentuemer-Konzept - jeder Thread kann signal() aufrufen, egal wer wait() aufgerufen hat.", difficulty = 3, funFact = "Das Semaphor-Konzept erfand Edsger Dijkstra 1965. Er nannte die Operationen P (proberen = testen) und V (verhogen = erhoehen) nach niederlaendischen Woertern."),
    Question(categoryId = 7, questionText = "Was ist ein Monad in der funktionalen Programmierung (praezise Definition)?", answerA = "Eine Datenstruktur fuer unveraenderliche verkettete Listen", answerB = "Ein Typ-Konstruktor M mit zwei Operationen: return (a -> M a) und bind (M a -> (a -> M b) -> M b), der drei Monad-Gesetze erfuellt", answerC = "Eine spezielle Art von Klasse ohne Vererbung und ohne Zustand", answerD = "Ein sprachinterner Mechanismus zur Fehlerbehandlung ohne Exceptions", correctAnswer = 1, explanation = "Ein Monad ist ein Typ-Konstruktor mit return/unit und bind (>>=), der drei Gesetze erfuellt: linke Identitaet, rechte Identitaet und Assoziativitaet. Beispiele: Maybe, IO, List, State.", difficulty = 3, funFact = "Philip Wadler popularisierte Monaden in der Programmiersprachen-Theorie 1992. Der beruehmt-bejammerte Satz 'A monad is just a monoid in the category of endofunctors' stammt von Saunders Mac Lane."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem optimistischen und pessimistischen Locking in Datenbanken?", answerA = "Optimistisches Locking sperrt Daten sofort beim Lesen und haelt die Sperre bis zum Commit", answerB = "Pessimistisches Locking sperrt Daten sofort beim Lesen und haelt die Sperre bis zum Commit; optimistisches prueft erst beim Schreiben auf Konflikte via Versionsnummer", answerC = "Optimistisches Locking ist grundsaetzlich immer langsamer als pessimistisches Locking", answerD = "Pessimistisches Locking ist nur in NoSQL-Datenbanken verfuegbar und nutzbar", correctAnswer = 1, explanation = "Pessimistisches Locking: Daten werden beim Lesen gesperrt (SELECT FOR UPDATE). Optimistisches Locking: Daten werden nicht gesperrt, aber beim Schreiben wird eine Versionsnummer geprueft - bei Konflikt Rollback.", difficulty = 3, funFact = "Optimistisches Locking ist effizienter bei seltenen Konflikten (z.B. seltene Updates). Pessimistisches ist besser bei haeufigen Konflikten um Rollback-Overhead zu vermeiden."),
    Question(categoryId = 7, questionText = "Was ist das Unterschied zwischen einem Semaphor und einem Monitor in der nebenlaeufen Programmierung?", answerA = "Ein Monitor ist lediglich ein Semaphor mit einem Zaehler groesser als 1", answerB = "Ein Monitor kombiniert gegenseitigen Ausschluss mit Condition Variables in einem einzigen Abstraktionsmechanismus; Semaphore sind niedrigstufiger und fehleranfaelliger in der Verwendung", answerC = "Monitore sind nur in Java verfuegbar, Semaphore hingegen in allen Sprachen", answerD = "Semaphore bieten mehr Sicherheit gegen Race Conditions als Monitore durch Zaehlsemantik", correctAnswer = 1, explanation = "Ein Monitor (Hoare, 1974) kapselt Daten, Prozeduren und impliziten Mutex. Condition Variables (wait/signal) erlauben geordnetes Warten. Java's synchronized-Methoden und C#'s lock sind Monitor-Implementierungen.", difficulty = 3, funFact = "Tony Hoare erfand Monitore 1974 als sicherere Alternative zu Semaphoren. Er beschrieb Semaphore als 'wie eine Motorsaege ohne Schutzvorrichtung'."),
    Question(categoryId = 7, questionText = "Was ist ein AVL-Baum und welche Invariante haelt er aufrecht?", answerA = "Ein binaerer Suchbaum dessen linker und rechter Teilbaum immer exakt gleich gross sind", answerB = "Ein selbstbalancierender binaerer Suchbaum wo fuer jeden Knoten die Hoehendifferenz zwischen linkem und rechtem Teilbaum maximal 1 betraegt", answerC = "Ein Baum mit maximal 2 Kindern pro Knoten der automatisch und nie manuell rebalanciert wird", answerD = "Ein Heap-geordneter Baum fuer effiziente Priority-Queue-Operationen", correctAnswer = 1, explanation = "AVL-Baeume halten die Balance-Invariante durch Rotationen (LL, LR, RL, RR) aufrecht. Garantierte O(log n) fuer Suche, Einfuegen und Loeschen. Besser ausbalanciert als Red-Black-Trees, aber mehr Rotationen beim Schreiben.", difficulty = 3, funFact = "AVL steht fuer Adelson-Velsky und Landis, die russischen Mathematiker die den Baum 1962 erfanden - 10 Jahre vor dem Red-Black-Tree."),
    Question(categoryId = 7, questionText = "Was ist formale Verifikation und welche Technik ist besonders fuer Software-Korrektheitsbeweis bekannt?", answerA = "Das automatische Testen von Software mit zufaellig generierten Testfaellen (Fuzzing)", answerB = "Der mathematische Beweis der Korrektheit eines Programms gegenueber einer formalen Spezifikation, typisch durch Model Checking oder Theorem Proving (z.B. Hoare-Logik)", answerC = "Die statische Analyse von Code auf potenzielle Nullpointer-Dereferenzierungen durch Linter", answerD = "Das Verifizieren von Softwareanforderungen durch manuelle Reviews und Code-Inspektionen", correctAnswer = 1, explanation = "Formale Verifikation benutzt mathematische Methoden: Hoare-Tripel {P} C {Q} beweist Pre-/Postconditions. Model Checker wie SPIN pruefen alle Zustandsuebergaenge. Isabelle/HOL und Coq sind Theorem-Prover.", difficulty = 3, funFact = "Das seL4-Microkernel-Projekt ist der erste vollstaendig formal verifizierte Betriebssystem-Kernel. Der Beweis hat 200.000 Zeilen Isabelle/HOL und dauerte 20 Personen-Jahre."),
    Question(categoryId = 7, questionText = "Was ist ein Read-Write-Lock und wann ist er effizienter als ein normaler Mutex?", answerA = "Ein Read-Write-Lock ist grundsaetzlich immer langsamer als ein Mutex wegen des Verwaltungs-Overheads", answerB = "Ein Read-Write-Lock erlaubt mehrere gleichzeitige Leser oder exklusiven Schreibzugriff; er ist effizienter wenn Lesezugriffe deutlich haeufiger sind als Schreibzugriffe", answerC = "Ein Read-Write-Lock erlaubt mehrere gleichzeitige Schreiber, aber nur jeweils einen Leser", answerD = "Read-Write-Locks werden ausschliesslich in Datenbanken und nicht in Anwendungscode eingesetzt", correctAnswer = 1, explanation = "RW-Locks trennen Lese- und Schreibzugriff: n gleichzeitige Leser sind erlaubt, ein Schreiber erfordert exklusiven Zugriff. Ideal wenn 90%+ der Zugriffe Reads sind (z.B. Caches, Konfiguration).", difficulty = 3, funFact = "Der klassische RW-Lock hat ein Writer-Starvation-Problem: Wenn immer neue Leser kommen, wartet der Schreiber ewig. Writer-Preference-Locks loesen dies, koennen aber Reader-Starvation verursachen."),
    Question(categoryId = 7, questionText = "Was ist das Observer-Pattern und wie unterscheidet es sich vom Publish-Subscribe-Pattern?", answerA = "Observer und Publish-Subscribe sind technisch identisch und koennen synonym verwendet werden", answerB = "Observer: direkter Aufruf von Subscriber-Methoden durch Observable; Publish-Subscribe: Nachrichten gehen durch einen Message Broker, Publisher kennt Subscriber nicht", answerC = "Observer verwendet Polling, Publish-Subscribe ausschliesslich asynchrone Push-Nachrichten", answerD = "Publish-Subscribe ist eine veraltete und ueberholte Version des Observer-Patterns", correctAnswer = 1, explanation = "Im Observer-Pattern registrieren sich Subscriber direkt beim Observable. Im Pub/Sub-Pattern gibt es einen Message Broker (Kafka, RabbitMQ): Publisher publiziert Topics, Subscriber abonniert Topics - Publisher und Subscriber kennen sich nicht.", difficulty = 3, funFact = "Das Observer-Pattern ist die Grundlage von RxJava, ReactiveX und allen Event-Listener-Systemen. Android's LiveData und Flow sind moderne Observer-Implementierungen."),
    Question(categoryId = 7, questionText = "Was ist das Hoare-Triple und wie wird es in der formalen Programmverifikation verwendet?", answerA = "Ein Dreischritt-Refaktorierungsverfahren aus dem Test-Driven Development: Red-Green-Refactor", answerB = "Die Notation {P} C {Q}: wenn Vorbedingung P gilt und Programm C ausgefuehrt wird, dann gilt Nachbedingung Q - dient zum mathematischen Beweisen von Programmkorrektheit", answerC = "Ein Algorithmus fuer prioritaetsbasiertes Thread-Scheduling in Echtzeitsystemen", answerD = "Ein Architekturmuster fuer die Konstruktion von drei miteinander kommunizierenden Prozessen", correctAnswer = 1, explanation = "C.A.R. Hoare (1969): {P} C {Q} bedeutet: 'Wenn P vor Ausfuehrung von C gilt, gilt Q danach.' Regeln fuer Zuweisungen, Sequenzen, Schleifen und Bedingungen erlauben den formalen Beweis.", difficulty = 3, funFact = "Tony Hoare erhielt 1980 den Turing Award. Er erfand neben Hoare-Logik auch Quicksort und Communicating Sequential Processes (CSP), die Grundlage fuer Go's Concurrency-Modell."),
    Question(categoryId = 7, questionText = "Was ist das Konzept von Software-Transactional Memory (STM)?", answerA = "Eine Datenbank-Technik fuer schnellere ACID-Transaktionen in OLTP-Systemen", answerB = "Ein Concurrency-Kontrollmechanismus der Speicherzugriffe in atomaren Transaktionen kapselt, aehnlich wie Datenbank-Transaktionen, ohne explizite Locks", answerC = "Ein Hardware-Feature moderner CPUs fuer Cache-Kohaerenz zwischen Kernen", answerD = "Ein Garbage-Collection-Verfahren fuer nebenlaefige Anwendungen ohne Stop-the-World-Pausen", correctAnswer = 1, explanation = "STM erlaubt atomare Lese-Schreib-Sequenzen ohne Locks: atomic { x = x + 1; y = y - 1 } entweder vollstaendig oder gar nicht. Haskell's STM, Clojure's refs. Bei Konflikten: automatischer Rollback und Retry.", difficulty = 3, funFact = "Haskell's STM gilt als eleganteste Implementierung. Sie nutzt Haskell's Typsystem (STM-Monad) um sicherzustellen, dass STM-Transaktionen keine Seiteneffekte haben koennen."),
    Question(categoryId = 7, questionText = "Was ist NUMA (Non-Uniform Memory Access) und welchen Einfluss hat es auf die Performance?", answerA = "NUMA beschreibt ein Speichermodell wo alle CPUs identisch schnellen Zugriff auf den gesamten Speicher haben", answerB = "NUMA beschreibt Multi-Prozessor-Systeme wo CPUs schnelleren Zugriff auf ihren lokalen Speicher haben als auf Speicher anderer CPU-Knoten", answerC = "NUMA ist ein Cache-Kohaerenzprotokoll ausschliesslich fuer Multi-Core-CPUs auf einem einzigen Die", answerD = "NUMA-Systeme koennen aufgrund ihrer Architektur keine virtuellen Maschinen hosten", correctAnswer = 1, explanation = "In NUMA-Systemen (typisch bei Multi-Socket-Servern) ist lokaler Speicherzugriff 2-4x schneller als Remote-Speicherzugriff. NUMA-aware Allokation (numactl) ist kritisch fuer High-Performance-Computing.", difficulty = 3, funFact = "Linux-Kernel hat eingebaute NUMA-Policies. Java's G1 und ZGC Garbage Collector sind NUMA-aware. AMD EPYC-Server mit 2 Sockets haben bis zu 8 NUMA-Knoten durch die Chiplet-Architektur."),
    Question(categoryId = 7, questionText = "Was beschreibt das Liskov-Substitutionsprinzip im Kontext von Contracts (Vor-/Nachbedingungen)?", answerA = "Subtypen duerfen Vorbedingungen verschaerfen und Nachbedingungen beliebig abschwaechen", answerB = "Subtypen muessen Vorbedingungen schwaecheroder gleich halten (mehr akzeptieren) und Nachbedingungen verstaerken oder gleich halten (mehr garantieren)", answerC = "Subtypen muessen identische Vor- und Nachbedingungen wie der Basistyp aufweisen", answerD = "Vorbedingungen duerfen in Subtypen vollstaendig weggelassen werden", correctAnswer = 1, explanation = "Contravariance der Vorbedingungen: Subtypes duerfen mehr akzeptieren (schwaecher). Covariance der Nachbedingungen: Subtypes muessen mindestens so viel garantieren (staerker). Verletzung: Override der Methode mit strengerer Vorbedingung.", difficulty = 3, funFact = "Design by Contract wurde von Bertrand Meyer fuer die Programmiersprache Eiffel entwickelt. Kotlin erlaubt Contract-Definitionen via kotlin.contracts fuer Compiler-Optimierungen."),
    // correctAnswer = 2 (12x: Fragen 27-38)
    Question(categoryId = 7, questionText = "Was ist die Laufzeitkomplexitaet des Floyd-Warshall-Algorithmus?", answerA = "O(V^2) mit optimierter Adjazenzmatrix", answerB = "O(V^2 log V) mit Fibonacci-Heap", answerC = "O(V^3) durch drei ineinandergeschachtelte Schleifen", answerD = "O(E * V) wie beim Bellman-Ford-Algorithmus", correctAnswer = 2, explanation = "Floyd-Warshall berechnet alle kuerzesten Pfade zwischen allen Knotenpaaren in O(V^3) mit O(V^2) Speicher. Er nutzt dynamische Programmierung und funktioniert auch mit negativen Kantengewichten (aber nicht negativen Zyklen).", difficulty = 3, funFact = "Der Algorithmus wurde unabhaengig von Robert Floyd und Stephen Warshall entwickelt. Floyd beschrieb ihn 1962 als einfache 3-zeilige Erweiterung einer Adjazenzmatrix."),
    Question(categoryId = 7, questionText = "Welche Sortierungsklasse hat im Worst Case O(n log n) garantiert und ist nicht vergleichsbasiert?", answerA = "Quicksort mit randomisierter Pivot-Auswahl", answerB = "Heapsort mit binaerer Heap-Struktur", answerC = "Counting Sort und Radix Sort als nicht-vergleichsbasierte Verfahren", answerD = "Merge Sort mit Bottom-Up-Implementierung", correctAnswer = 2, explanation = "Counting Sort und Radix Sort sind nicht-vergleichsbasierte Algorithmen mit O(n*k) Komplexitaet (k = Schluessel-Bereich). Sie umgehen die theoretische Untergrenze von O(n log n) fuer vergleichsbasierte Sortierverfahren.", difficulty = 3, funFact = "Die O(n log n)-Untergrenze fuer vergleichsbasierte Sortierung wurde durch die Informationstheorie bewiesen: n! moegliche Permutationen brauchen log2(n!) Vergleiche, was nach Stirling's Formel O(n log n) ergibt."),
    Question(categoryId = 7, questionText = "Welche Zeitkomplexitaet hat das Finden des kuerzesten Wegs mit dem Bellman-Ford-Algorithmus?", answerA = "O(V log E) durch primaere Heap-Optimierung", answerB = "O(E log V) durch Kantensortierung", answerC = "O(V * E) durch V-1 Iterationen je ueber alle Kanten", answerD = "O(V^2 + E) durch Adjazenzmatrix-Traversal", correctAnswer = 2, explanation = "Bellman-Ford hat O(V*E) Zeitkomplexitaet: V-1 Iterationen, jede prueft alle E Kanten. Langsamer als Dijkstra, aber kann negative Kantengewichte und negative Zyklen erkennen.", difficulty = 3, funFact = "Bellman-Ford wird im Routing Protocol RIP (Routing Information Protocol) eingesetzt. Jeder Router ist ein Knoten, jede Netzwerkverbindung eine Kante."),
    Question(categoryId = 7, questionText = "Was ist ein Bloom-Filter und welche Einschraenkung hat er gegenueber einer Hash-Tabelle?", answerA = "Ein Bloom-Filter ist exakter als eine Hash-Tabelle, braucht aber deutlich mehr Speicher", answerB = "Ein Bloom-Filter erlaubt das Loeschen von Elementen, Hash-Tabellen nicht", answerC = "Ein Bloom-Filter ist eine platzsparende Datenstruktur mit moeglichen False Positives (kann sagen 'vielleicht drin' wenn nicht drin), aber keinen False Negatives", answerD = "Ein Bloom-Filter hat O(n) Lookup-Komplexitaet gegenueber O(1) bei Hash-Tabellen", correctAnswer = 2, explanation = "Ein Bloom-Filter nutzt k Hash-Funktionen auf einem Bit-Array. False Positives sind moeglich (Bit-Kollisionen), aber False Negatives sind ausgeschlossen. Loeschen ist nicht moeglich ohne einen Counting Bloom Filter.", difficulty = 3, funFact = "Google Chrome nutzt Bloom-Filter fuer die Pruefliste schaedlicher URLs. Die lokale Datenbank hat eine akzeptable False-Positive-Rate, echte Treffer werden dann serverseitig verifiziert."),
    Question(categoryId = 7, questionText = "Was ist das Hindley-Milner-Typsystem und was macht es besonders?", answerA = "Ein dynamisches Typsystem vergleichbar mit JavaScript's Typsystem", answerB = "Ein Typsystem das ausschliesslich primitive Typen unterstuetzt", answerC = "Ein Typsystem das vollstaendige Typinferenz garantiert: Typen koennen ohne explizite Annotationen inferiert werden, waehrend statische Typsicherheit erhalten bleibt", answerD = "Ein Typsystem fuer objektorientierte Sprachen mit Mehrfachvererbung wie C++", correctAnswer = 2, explanation = "Hindley-Milner (1969/1978) erlaubt vollstaendige Typinferenz durch Algorithm W. Haskell, ML, OCaml und F# basieren darauf. Der Compiler leitet jeden Typ ab, ohne dass der Programmierer Annotationen schreiben muss.", difficulty = 3, funFact = "Algorithm W laeuft in fast-linearer Zeit. Roger Hindley entdeckte das System 1969, Robin Milner implementierte es 1978 fuer ML. Beide forschten unabhaengig voneinander."),
    Question(categoryId = 7, questionText = "Was ist ein B-Baum und warum wird er in Datenbank-Indizes bevorzugt?", answerA = "Ein B-Baum ist ein balancierter binaerer Suchbaum mit einer fest vorgegebenen Knotengroesse", answerB = "Ein B-Baum ist eine Variante von AVL-Baeumen mit geringerem Speicherbedarf", answerC = "Ein B-Baum ist ein selbstbalancierender Baum mit mehreren Schluesseln pro Knoten und hohem Verzweigungsgrad, optimiert fuer blockorientierte Speichermedien wie Festplatten", answerD = "B-Baeume werden ausschliesslich im Hauptspeicher (RAM) verwendet und nicht auf Festplatten", correctAnswer = 2, explanation = "B-Baeume haben hohen Branching Factor (hunderte Schluessel pro Knoten) - eine Baumhoehe von 3-4 reicht fuer Millionen von Eintraegen. Knotengroesse entspricht einer Disk-Page und minimiert I/O-Operationen.", difficulty = 3, funFact = "PostgreSQL, MySQL/InnoDB und SQLite verwenden alle B+-Baeume (Variante: alle Daten in Blattknoten). Das 'B' steht nie klar: Bayer (Erfinder), balanced, broad oder Boeing wurden alle vorgeschlagen."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Stack-basierten und einem Register-basierten Virtual Machine Design?", answerA = "Register-basierte VMs sind grundsaetzlich immer langsamer als Stack-basierte VMs", answerB = "Stack-basierte VMs sind moderner und ersetzen Register-basierte VMs vollstaendig", answerC = "Stack-basierte VMs (JVM, Python) verwenden einen impliziten Operanden-Stack; Register-basierte VMs (Dalvik/ART, Lua) verwenden explizite Register und benoetigen weniger Instruktionen", answerD = "Register-basierte VMs koennen prinzipiell nicht auf realer Hardware ausgefuehrt werden", correctAnswer = 2, explanation = "Stack-VMs: einfacher zu implementieren, mehr Instruktionen (PUSH/POP). Register-VMs: weniger Instruktionen, direkter auf CPU-Register mappbar, schneller. Android wechselte von Stack-VM (Dalvik) zu Register-VM (ART).", difficulty = 3, funFact = "Google entwickelte Dalvik als Register-VM speziell fuer mobile Geraete mit begrenztem RAM. ART (Android Runtime) ersetzte Dalvik 2014 und fuegt AOT-Kompilierung hinzu."),
    Question(categoryId = 7, questionText = "Was ist das Konzept der Parametric Polymorphism (Generics) und warum ist es typsicherer als Object-basierter Code?", answerA = "Generics sind grundsaetzlich langsamer als Object-basierter Code wegen Typ-Pruefungen zur Laufzeit", answerB = "Parametric Polymorphism ist ausschliesslich in funktionalen Sprachen wie Haskell moeglich", answerC = "Parametric Polymorphism erlaubt Algorithmen und Datenstrukturen die ueber Typen parametrisiert werden, ohne Typinformation zur Laufzeit zu verlieren - vermeidet Cast-Fehler", answerD = "Generics verhindern jede Form von Ad-hoc-Polymorphismus", correctAnswer = 2, explanation = "List<String> ist typsicher: kein Cast noetig, Fehler werden zur Compile-Zeit erkannt. List<Object> erfordert Casts und kann ClassCastException zur Laufzeit werfen. Java's Type Erasure entfernt Typ-Parameter zur Laufzeit fuer Rueckwaertskompatibilitaet.", difficulty = 3, funFact = "C# Generics sind 'reified' (Typinformation bleibt zur Laufzeit erhalten). Java nutzt Type Erasure fuer Rueckwaertskompatibilitaet mit Java 1.4, was Limitierungen wie 'new T()' unmoeglich macht."),
    Question(categoryId = 7, questionText = "Was ist Amortisierte Analyse und wie unterscheidet sie sich von Worst-Case-Analyse?", answerA = "Amortisierte Analyse ist vollstaendig identisch mit Average-Case-Analyse ueber zufaellige Eingaben", answerB = "Amortisierte Analyse gilt nur fuer parallele und nebenlaefige Algorithmen", answerC = "Amortisierte Analyse berechnet die durchschnittliche Laufzeit einer Operation ueber eine Sequenz von Operationen, nicht den Worst-Case einer einzelnen Operation", answerD = "Amortisierte Analyse liefert garantiert immer bessere Schranken als Worst-Case-Analyse", correctAnswer = 2, explanation = "ArrayList.add() hat O(n) Worst-Case (Reallokation), aber O(1) amortisiert: seltene O(n)-Operationen werden auf viele O(1)-Operationen verteilt. Methoden: Aggregat-, Bankkonto- und Potenzial-Methode.", difficulty = 3, funFact = "Der Begriff wurde 1985 von Robert Tarjan gepraegt. Selbstjustierende Datenstrukturen wie Splay Trees haben nur amortisiert O(log n), aber O(n) Worst-Case pro Operation."),
    Question(categoryId = 7, questionText = "Was ist ein Segment-Tree und welche Probleme loest er effizient?", answerA = "Ein Segment-Tree ist eine Variante des B+-Trees fuer Datenbank-Indizes", answerB = "Segment-Trees werden ausschliesslich fuer geometrische Bereichsschnittprobleme eingesetzt", answerC = "Ein Segment-Tree loest Range-Query-Probleme (z.B. Bereichssumme, Bereichsminimum) in O(log n) pro Query und O(log n) pro Update", answerD = "Ein Segment-Tree benoetigt O(n^2) Speicherplatz fuer n Elemente", correctAnswer = 2, explanation = "Ein Segment-Tree auf Array A[0..n-1] erlaubt: Range-Sum-Query(l, r) in O(log n), Point-Update(i, val) in O(log n). Alternativ: Fenwick Tree (BIT) ist einfacher implementiert fuer gleiche Komplexitaet.", difficulty = 3, funFact = "Segment-Trees werden extensiv in Competitive Programming eingesetzt. Eine 'Lazy Propagation'-Variante erlaubt sogar Range-Updates in O(log n) statt O(n)."),
    Question(categoryId = 7, questionText = "Was ist Priority Inversion und wie wird es durch Priority Inheritance geloest?", answerA = "Priority Inversion ist eine gezielte CPU-Scheduling-Optimierung fuer Echtzeitsysteme", answerB = "Priority Inversion tritt ausschliesslich in Systemen ohne Betriebssystem-Kernel auf", answerC = "Priority Inversion tritt auf wenn ein hoch-priorisierter Thread auf einen Mutex wartet der von einem niedrig-priorisierten Thread gehalten wird, der wiederum von einem mittel-priorisierten Thread verdraengt werden kann", answerD = "Priority Inheritance erhoeh immer die Prioritaet aller im System laufenden Threads auf Maximum", correctAnswer = 2, explanation = "Priority Inversion: High (H) wartet auf Mutex von Low (L). Medium (M) verdraengt L. H haengt! Priority Inheritance: L erbt H's Prioritaet temporaer. Beruehmt durch Mars Pathfinder Bug 1997.", difficulty = 3, funFact = "Der Mars Pathfinder Rover von 1997 hatte einen Priority Inversion Bug der regelmaessige Systemresets verursachte. NASA loeste ihn aus der Ferne durch Aktivierung von Priority Inheritance in VxWorks."),
    Question(categoryId = 7, questionText = "Was ist das Open/Closed Principle (OCP) in SOLID?", answerA = "Klassen sollen fuer alle externen Zugriffe vollstaendig oeffentlich zugaenglich sein", answerB = "Methoden sollen entweder als open source oder als closed source veroffentlicht werden", answerC = "Software-Module sollen offen fuer Erweiterung durch neue Subklassen sein, aber geschlossen gegenueber Aenderungen an bestehendem produktivem Code", answerD = "Interfaces sollen offen definiert, deren Implementierungen vollstaendig geschlossen gehalten werden", correctAnswer = 2, explanation = "Das OCP von Bertrand Meyer (1988) besagt: Erweiterung durch neue Klassen/Implementierungen ja, Aenderung an bestehendem Code nein. Strategien: Vererbung, Komposition, Dependency Injection.", difficulty = 3, funFact = "Robert C. Martin reformulierte das OCP durch Polymorphismus: Verhaltensaenderung durch neue Implementierungen eines Interfaces, nicht durch Modifikation bestehender Klassen."),
    // correctAnswer = 3 (12x: Fragen 39-50)
    Question(categoryId = 7, questionText = "Was ist bedeutet Referential Transparency in der funktionalen Programmierung?", answerA = "Alle Variablen zeigen direkt auf den Speicherbereich ohne Pointer-Indirektion", answerB = "Referenzen auf Objekte bleiben ueber den gesamten Objektlebenszyklus unveraendert", answerC = "Funktionen duerfen ausschliesslich lesend auf globale Variablen zugreifen", answerD = "Ein Funktionsaufruf kann durch seinen Rueckgabewert ersetzt werden ohne das Programmverhalten zu aendern, weil die Funktion keine Seiteneffekte hat", correctAnswer = 3, explanation = "Referential Transparency: f(x) kann ueberall durch seinen Wert ersetzt werden. Dies setzt voraus, dass f keine Seiteneffekte hat und bei gleichen Eingaben immer gleiche Ausgaben liefert. Grundlage fuer Memoization und parallele Ausfuehrung.", difficulty = 3, funFact = "Der Begriff stammt aus der Philosophie von Leibniz (Principle of Substitutivity). Willard van Orman Quine adaptierte ihn 1956 fuer die Logik, bevor er in die Informatik einging."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Parallelitaet (Parallelism) und Nebenlaefigkeit (Concurrency)?", answerA = "Concurrency und Parallelism sind vollstaendige Synonyme und beschreiben dasselbe Konzept", answerB = "Parallelism ist nur in funktionalen Sprachen wie Haskell moeglich, Concurrency in allen", answerC = "Concurrency erfordert immer mehrere Betriebssystem-Prozesse, Parallelism nur Threads", answerD = "Concurrency ist die Faehigkeit mehrere Aufgaben gleichzeitig zu verwalten (muss nicht simultan sein); Parallelism ist die echte simultane Ausfuehrung auf mehreren CPUs", correctAnswer = 3, explanation = "Rob Pike's Unterscheidung: Concurrency ist das Strukturieren von Code fuer potenzielle Gleichzeitigkeit (Go Goroutines). Parallelism ist die Hardware-Ausfuehrung (Multi-Core). Concurrency ohne Parallelism: Single-Core-Multithreading.", difficulty = 3, funFact = "Rob Pike erklaerte es mit Mokka-Zubereitungs-Analogie: Concurrency = Aufgaben koordinieren; Parallelism = Aufgaben gleichzeitig erledigen. Concurrency ermoeglicht Parallelism, erzwingt ihn aber nicht."),
    Question(categoryId = 7, questionText = "Was ist das CAP-Theorem fuer ein verteiltes System?", answerA = "Ein System kann gleichzeitig Consistency, Availability und Partition Tolerance vollstaendig und ohne Kompromisse garantieren", answerB = "Partition Tolerance ist optional und kann durch ausreichend Redundanz vollstaendig ersetzt werden", answerC = "Das CAP-Theorem gilt ausschliesslich fuer relationale Datenbanken", answerD = "Ein System kann bei Netzwerkpartitionierung nur zwei von drei Eigenschaften (Consistency, Availability, Partition Tolerance) gleichzeitig garantieren", correctAnswer = 3, explanation = "Eric Brewer formulierte das CAP-Theorem 2000: Bei einer Netzwerkpartitionierung (P) muss ein System waehlen zwischen Konsistenz (C) und Verfuegbarkeit (A). CP-Systeme: HBase, Zookeeper. AP-Systeme: Cassandra, CouchDB.", difficulty = 3, funFact = "Das Theorem wurde 2002 von Gilbert und Lynch formal bewiesen. Heute gilt PACELC als praeziseres Modell, das auch Latenz-Konsistenz-Tradeoffs ohne Partition einschliesst."),
    Question(categoryId = 7, questionText = "Was ist das Visitor-Pattern und wann ist es vorteilhafter als direkte Methodenueberladung?", answerA = "Das Visitor-Pattern wird ausschliesslich fuer XML- und JSON-Verarbeitung eingesetzt", answerB = "Visitor ist aufgrund doppelter Dispatch-Kosten immer langsamer als direkte Methodenaufrufe", answerC = "Das Visitor-Pattern ist funktional identisch mit dem Iterator-Pattern", answerD = "Das Visitor-Pattern erlaubt neue Operationen auf einer Objektstruktur hinzuzufuegen ohne die Klassen zu aendern - vorteilhaft wenn Operationen haeufig erweitert werden, Typen aber stabil bleiben", correctAnswer = 3, explanation = "Double Dispatch: Element.accept(visitor) → visitor.visit(concreteElement). Vorteil: neue Operationen (Visitor) ohne Aenderung der Element-Klassen. Nachteil: neue Element-Typen erfordern Aenderungen aller Visitor.", difficulty = 3, funFact = "AST (Abstract Syntax Tree) Verarbeitung in Compilern ist der klassische Visitor-Anwendungsfall. Kotlin's when-Expression auf sealed classes bietet eine elegantere Alternative ohne explizites Visitor-Pattern."),
    Question(categoryId = 7, questionText = "Was ist das Command-Pattern und welchen Vorteil bietet es fuer Undo/Redo-Funktionalitaet?", answerA = "Das Command-Pattern wird ausschliesslich fuer die Verarbeitung von CLI-Befehlen verwendet", answerB = "Das Command-Pattern erfordert grundsaetzlich immer einen separaten dedizierten Invoker-Thread", answerC = "Das Command-Pattern und das Strategy-Pattern sind funktional identisch und austauschbar", answerD = "Das Command-Pattern kapselt eine Anfrage als Objekt, was das Speichern, Rueckgaengigmachen (Undo) und Wiederherstellen (Redo) von Operationen ermoeglicht", correctAnswer = 3, explanation = "Command-Objekte kapseln execute() und undo(). Eine History-Liste speichert ausgefuehrte Commands. Undo: ruft undo() des letzten Commands auf. Redo: ruft execute() des naechsten Commands auf.", difficulty = 3, funFact = "GUI-Frameworks wie Qt und WPF implementieren Undo/Redo mit dem Command-Pattern. Datenbank-Transaktionslogs sind ebenfalls Command-Sequenzen die Rollback und Recovery ermoeglichen."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Hypervisor und einem Container-Runtime wie Docker?", answerA = "Container bieten staerkere Hardware-Isolation als Hypervisoren", answerB = "Hypervisoren koennen aufgrund ihrer Architektur keine Linux-Gastbetriebssysteme hosten", answerC = "Docker-Container und virtuelle Maschinen haben identische Performance-Charakteristiken", answerD = "Hypervisoren virtualisieren Hardware und laufen eigenstaendige OS-Instanzen; Container teilen den Host-OS-Kernel und sind leichtgewichtiger aber weniger isoliert", correctAnswer = 3, explanation = "VMs: vollstaendige OS-Isolation, eigener Kernel, MB bis GB overhead, Sekunden-Startzeit. Container: Namespaces + cgroups fuer Prozessisolation, gemeinsamer Kernel, MB Overhead, Millisekunden-Startzeit.", difficulty = 3, funFact = "Linux-Namespaces (PID, Net, Mnt, UTS, IPC, User) und cgroups (Ressourcenlimits) bilden die technische Basis aller Container. Docker besteht im Kern aus diesen Linux-Kernel-Features."),
    Question(categoryId = 7, questionText = "Was ist das Composite-Pattern und in welchem Anwendungsfall ist es besonders geeignet?", answerA = "Das Composite-Pattern kombiniert mehrere Objekte zu einem gemeinsamen Proxy-Objekt", answerB = "Das Composite-Pattern ist eine Variante des Abstract-Factory-Patterns fuer komplexe Objekte", answerC = "Das Composite-Pattern wird ausschliesslich fuer UI-Komponenten in Desktop-Anwendungen geeignet", answerD = "Das Composite-Pattern erlaubt die Behandlung von einzelnen Objekten und Kompositionen gleichartig durch eine gemeinsame Schnittstelle - geeignet fuer Baumstrukturen", correctAnswer = 3, explanation = "Composite: Blatt und Komposit implementieren die gleiche Schnittstelle. Dateiverzeichnis-Hierarchien, UI-Komponentenbaeume (Android View/ViewGroup), JSON-Baumstrukturen sind typische Anwendungsgebiete.", difficulty = 3, funFact = "Android's View-Hierarchie ist ein Composite-Pattern: View (Blatt) und ViewGroup (Komposit) erben beide von View. draw(), measure() und layout() werden rekursiv durch den gesamten Baum aufgerufen."),
    Question(categoryId = 7, questionText = "Was ist das Konzept der Immutability in funktionaler Programmierung und welche Vorteile bietet es?", answerA = "Immutability macht Programme grundsaetzlich langsamer wegen staendiger vollstaendiger Objektkopien", answerB = "Immutability ist ausschliesslich in Sprachen ohne Garbage Collector wie Rust sinnvoll", answerC = "Immutable Objekte koennen per Definition keine Methoden oder Verhaltenslogik haben", answerD = "Immutable Daten koennen nach der Erstellung nicht mehr veraendert werden, was Thread-Safety garantiert, Caching ermoeglicht und Reasoning vereinfacht", correctAnswer = 3, explanation = "Immutability garantiert: keine Race Conditions, sicheres Sharing zwischen Threads, freie Memoization, Vereinfachung von Debugging. Persistent Data Structures (wie Clojures Vektoren) teilen Strukturen statt zu kopieren.", difficulty = 3, funFact = "Kotlins data class mit val-Feldern und Java's record (Java 16) sind immutable by design. Clojure's persistente Datenstrukturen (Phil Bagwell's Hash Array Mapped Tries) erreichen O(log32 n) durch strukturelles Teilen."),
    Question(categoryId = 7, questionText = "Was ist das Dependency-Injection-Prinzip und worin unterscheidet sich Constructor Injection von Field Injection?", answerA = "Field Injection ist stets vorzuziehen wegen wesentlich weniger Boilerplate-Code", answerB = "Constructor Injection wird ausschliesslich in funktionalen Sprachen wie Haskell eingesetzt", answerC = "Dependency Injection erfordert grundsaetzlich immer ein externes Framework wie Spring oder Hilt", answerD = "Constructor Injection injiziert Abhaengigkeiten ueber den Konstruktor (explizit, testbar, immutable); Field Injection injiziert direkt in Felder via Annotation (weniger Boilerplate, aber schwerer testbar)", correctAnswer = 3, explanation = "Constructor Injection macht Abhaengigkeiten explizit, ermoeglicht Immutability und erleichtert Unit-Tests ohne Framework. Field Injection (Hilt, Spring @Autowired) reduziert Boilerplate, erschwert aber das manuelle Testen.", difficulty = 3, funFact = "Die Android-Dokumentation empfiehlt seit 2020 explizit Constructor Injection ueber Field Injection, da es testbaren Code ohne Hilt-Testmodule ermoeglicht."),
    Question(categoryId = 7, questionText = "Was ist Phantom-Read-Anomalie in Datenbank-Transaktionen und welches Isolation Level verhindert sie?", answerA = "Phantom Reads treten ausschliesslich bei UPDATE-Statements und nicht bei SELECT-Statements auf", answerB = "READ COMMITTED Isolation Level verhindert Phantom Reads vollstaendig und zuverlaessig", answerC = "Phantom Reads koennen nur bei Single-Table-Queries und nicht bei Joins auftreten", answerD = "Eine Phantom-Read-Anomalie tritt auf wenn eine Transaktion bei wiederholtem Lesen eines Bereichs neue Zeilen findet die eine andere Transaktion eingefuegt hat - verhindert durch SERIALIZABLE Isolation Level", correctAnswer = 3, explanation = "Bei REPEATABLE READ koennen neue Zeilen im selben Range durch andere Transaktionen auftreten (Phantom). SERIALIZABLE verhindert dies durch Bereichssperren oder Snapshot Isolation. PostgreSQL's REPEATABLE READ verhindert Phantoms durch MVCC.", difficulty = 3, funFact = "SQL-Standard definiert 4 Isolation Levels: READ UNCOMMITTED, READ COMMITTED, REPEATABLE READ, SERIALIZABLE. Die meisten Datenbanken verwenden READ COMMITTED als Default. MySQL/InnoDB nutzt REPEATABLE READ als Default."),
    Question(categoryId = 7, questionText = "Was ist ein Software-Design-Pattern der Kategorie 'Behavioral' und was sind seine Merkmale?", answerA = "Behavioral Patterns befassen sich ausschliesslich mit der Objekterzeugung (Factory, Singleton, Builder)", answerB = "Behavioral Patterns strukturieren Klassen und Objekte durch Komposition (Adapter, Bridge, Composite)", answerC = "Behavioral Patterns sind ausschliesslich in objektorientierten Sprachen und nicht in funktionalen Sprachen anwendbar", answerD = "Behavioral Patterns beschreiben Kommunikation und Verantwortungsverteilung zwischen Objekten (Observer, Strategy, Command, Iterator)", correctAnswer = 3, explanation = "Die GoF-Patterns werden in drei Kategorien eingeteilt: Creational (Erzeugung), Structural (Struktur) und Behavioral (Verhalten). Behavioral Patterns loesen Kommunikationsprobleme: Observer entkoppelt Publisher/Subscriber, Strategy macht Algorithmen austauschbar.", difficulty = 3, funFact = "Das Gang of Four (GoF) Buch 'Design Patterns: Elements of Reusable Object-Oriented Software' von Gamma, Helm, Johnson und Vlissides (1994) definierte 23 Patterns die noch heute als Standard gelten."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Interpreter und einem JIT-Compiler?", answerA = "JIT-Compiler sind grundsaetzlich immer langsamer als Interpreter wegen des Kompilierungs-Overheads", answerB = "JIT-Compiler kompilieren den gesamten Code vollstaendig vor der Ausfuehrung, Interpreter schrittweise", answerC = "Interpreter koennen prinzipiell keinen Bytecode verarbeiten und benoetigen Quellcode", answerD = "Ein Interpreter fuehrt Bytecode direkt aus; ein JIT-Compiler kompiliert haeufig ausgefuehrte Codebereiche zur Laufzeit in Maschinencode fuer deutlich hoehere Ausfuehrungsgeschwindigkeit", correctAnswer = 3, explanation = "JVM HotSpot erkennt 'hot paths' (haeufig ausgefuehrter Code) und kompiliert sie mit Optimierungen (Inlining, Escape Analysis) zu Maschinencode. Ergebnis: Java naehert sich C++ Performance nach dem Warmup.", difficulty = 3, funFact = "V8 (JavaScript in Chrome/Node.js) hat mehrere JIT-Tiers: Ignition (Interpreter) → Sparkplug (Baseline JIT) → Maglev → Turbofan (optimierend). Code steigt automatisch hoch und runter je nach Profiling-Daten.")
)
